部署Tomcat服务 Tomcat官网 8.3.x版本Tomcat安装包 安装Tomcat前准备 1.1 创建Tomcat启动用户 $ groupadd myadmin &amp;&amp; useradd -g myadmin myadmin $ echo &#34;20210627@123&#34;|passwd --stdin myadmin &amp;&gt;/dev/null $ echo &#34;#########Start/Stop Service############### Cmnd_Alias MYADMIN_START_SERVICES = /etc/init.d/nginx, /etc/init.d/tomcat, /opt/* /usr/bin/kill myadmin ALL=(ALL)NOPASSWD:MYADMIN_START_SERVICES&#34; &gt; /etc/sudoers.d/myadmin $ chmod 660 /etc/sudoers.d/myadmin 1.2 创建Tomcat部署目录 $ mkdir -p /opt/{data,apps,src,deploy,scripts,logs/tomcat} 1.3 检测JDK环境 $ yum list |grep openjdk # 包有 @ 代表安装 $ echo &#34;#######JDK環境變數######################## export JAVA_HOME=/opt/data/jdk export JRE_HOME=$JAVA_HOME/jre export CLASSPATH=$JAVA_HOME/lib:$JAVA_HOME/lib/tools.jar export PATH=$PATH:$JAVA_HOME/bin:$JAVA_HOME/jre/bin CATALINA_HOME=/opt/data/tomcat # 部署多实例启动脚本应用 export CATALINA_HOME &#34;&gt;&gt;/home/myadmin/.bash_profile $ source /home/myadmin/.bash_profile $ ln -s /opt/data/jdk/bin/java /sbin/java # 使jar包可以直接运行,后面做软连接,授权 下载安装Tomcat 2.1 下载Tomcat安装包 $ wget -P /opt/src/ https://archive.apache.org/dist/tomcat/tomcat-8/v8.5.35/bin/apache-tomcat-8.5.35.tar.gz $ wget -P /opt/src/ https://archive.apache.org/dist/tomcat/tomcat-8/v8.5.35/bin/apache-tomcat-8.5.35.tar.gz.sha512 2.2 检测安装包完整性 # md5sum -c apache-tomcat-6.0.35.tgz.md5 $ sha512sum -c apache-tomcat-8.5.35.tar.gz.sha512 2.3 解压以及更改权限 # ln -s /opt/lucky/apache-tomcat-8.5.35 /opt/data/tomcat # 可做软连接 $ tar -zxvf /opt/src/apache-tomcat-8.5.35.tar.gz -C /opt/data/ 2.4 修改Tomcat主配置文件 $ sed -i &#34;s/8080/8000/g&#34; /opt/data/tomcat/conf/server.xml $ sed -i &#39;s/logs//opt/data/logs/tomcat/g&#39; /opt/data/tomcat/conf/server.xml 2.5 修改Tomcat的Cataline.sh文件 $ sed -i &#39;/# OS specific support/iJAVA_OPTS=&#34;-Dfile.encoding=UTF-8 -server -Xms2048m -Xmx2048m -Xmn1024m -XX:SurvivorRatio=10 -XX:MaxTenuringThreshold=15 -XX:NewRatio=2 -XX:+DisableExplicitGC&#34;&#39; /opt/data/tomcat/bin/catalina.sh $ sed -i &#39;s/&#34;$CATALINA_BASE&#34;/logs/catalina.out//opt/data/logs/tomcat/catalina.out/g&#39; /opt/data/tomcat/bin/catalina.sh # sed -i &#39;/ &lt;/Host&gt;/i\ &lt;Context path=&#34;/&#34; docBase=&#34;/opt/lucky/publish-luckybackend&#34; reloadable=&#34;true&#34;&gt;&lt;/Context&gt;&#39; /opt/data/tomcat/conf/server.xml $ sed -i &#39;s/${catalina.base}/logs//opt/data/logs/tomcat/g&#39; /opt/data/tomcat/conf/logging.properties 2.6 防火墙开放端口 2.6.1 8005：端口是tomcat本身管理端口，修改一个不易猜到 2.6.2 8080：端口是tomcat负责建立HTTP连接。在通过浏览器访问tomcat服务器的web应用时，使用的就是这个端口 2.6.3 8009：tomcat负责和其他的HTTP服务器建立连接，如nginx和apache互通使用 $ firewall-cmd --permanent --new-ipset=tomcat_whitelist --type=hash:ip $ firewall-cmd --permanent --add-rich-rule=&#34;rule family=&#39;ipv4&#39; source ipset=&#39;tomcat_whitelist&#39; port prot=&#39;7000-7007&#39; protocol=&#39;tcp&#39; accept&#34; $ firewall-cmd --reload 2.7 网站根目录以及连接数据库 # 默认网站的主目录 $ ls /usr/local/tomcat/webapps/ $ cat &gt;/usr/local/tomcat/webapps/ROOT/WEB-INF/config/jdbc.properties&lt;&lt;-EOF # jdbc.url=jdbc:mysql://192.168.213.50:16303/jspgou?characterEncoding=UTF-8 # jspgou代表数据库 # jdbc.username=root # jdbc.password=123 EOF 2.8 启动Tomcat $ /opt/data/tomcat/bin/startup.sh 编写Tomcat启动文件 $ cat &gt;tomcat.sh&lt;&lt;-EOF #!/bin/bash TOMCAT_PATH=/usr/local/tomcat usage(){ echo &#34;Usage: $0 [start|stop|status|restart]&#34; } status_tomcat(){ ps aux | grep java | grep tomcat | grep -v &#39;grep&#39; } start_tomcat(){ /usr/local/tomcat/bin/startup.sh } stop_tomcat(){ TPID=$(ps aux | grep java | grep tomcat | grep -v &#39;grep&#39; | awk &#39;{print $2}&#39;) kill -9 $TPID sleep 5; TSTAT=$(ps aux | grep java | grep tomcat | grep -v &#39;grep&#39; | awk &#39;{print $2}&#39;) if [ -z $TSTAT ];then echo &#34;tomcat stop&#34; else kill -9 $TSTAT fi cd $TOMCAT_PATH rm temp/* -rf rm work/* -rf } main(){ case $1 in start) start_tomcat;; stop) stop_tomcat;; status) status_tomcat;; restart) stop_tomcat &amp;&amp; start_tomcat;; *) usage; esac } main $1 EOF 3.1 多端口启动Tomcat $ cat &gt;tomcat&lt;&lt;-EOF #!/bin/bash ## 此脚本用来启动停止以及查看tomcat多实例 ## 2021/04/18 author：Neek export JAVA_HOME=/opt/lucky/jdk export JRE_HOME=$JAVA_HOME/jre export CLASSPATH=$JAVA_HOME/lib:$JAVA_HOME/lib/tools.jar export PATH=$PATH:$JAVA_HOME/bin:$JAVA_HOME/jre/bin ## 目录 CATALINA_BASE=&#39;/opt/lucky/tomcat/&#39; WEBAPPS_PATH=&#39;/opt/lucky/tomcat/webapps&#39; CATALINA_HOME=&#39;/opt/lucky/tomcat/&#39; . /etc/init.d/functions read -p &#34;请输入要启动的的端口号，8080,6000，7000~7007，8818：&#34; port case $port in 8080) export CATALINA_BASE=&#34;/opt/lucky/tomcat&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 8080 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 6000) export CATALINA_BASE=&#34;/opt/lucky/tomcat/6000/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 6000 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7000) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7000/&#34; read -p &#34;启动停止tomcat确定吗？确定请输入操作指令(start/stop/restart)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7000 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7001) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7001/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7001 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7002) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7002/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7002 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7003) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7003/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7003 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7004) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7004/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7004 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7005) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7005/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7005 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7006) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7006/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7006 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 7007) export CATALINA_BASE=&#34;/opt/lucky/tomcat/7007/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 7007 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; 8818) export CATALINA_BASE=&#34;/opt/lucky/tomcat/8818/&#34; read -p &#34;启动停止tomcat以及查看状态，确定请输入操作指令(start/stop/restart/status)：&#34; port_st case &#34;$port_st&#34; in start) $CATALINA_HOME/bin/startup.sh ;; stop) $CATALINA_HOME/bin/shutdown.sh ;; restart) $CATALINA_HOME/bin/shutdown.sh sleep 5 $CATALINA_HOME/bin/startup.sh ;; status) tomcat_status=$(ss -unplt |egrep 8818 |egrep -i listen) [ -z &#34;$tomcat_status&#34; ] &amp;&amp; echo -e &#34;
tomcat\033[31m start failed ...\033[0m
&#34; || echo -e &#34;
tomcat\033[32m is running ...\033[0m
&#34; ;; esac;; esac export JAVA_OPTS=&#39;-Xms64m -Xmx128m&#39; EOF

数据库备份、还原、以及定时备份 使用mysqldump备份数据库 手动备份 # 备份用户权限 $ GRANT SELECT,RELOAD,LOCK TABLES,REPLICATION CLIENT,SHOW VIEW,EVENT,TRIGGER,PROCESS ON *.* TO &#39;backup&#39;@&#39;localhost&#39; identified BY &#39;passwoord&#39;; # 备份多个数据库 $ /bin/mysql -u root -p&#39;password&#39; \ -S /opt/data/data_16303/mysql.sock -e &#39;show databases;&#39;| \ grep -E -v &#34;sys|mysql|information_schema|performance_schema|Database&#34; \ |grep -E &#34;.*datebases1$|.*datebases2$&#34; | \ xargs /bin/mysqldump -u root -p&#39;password&#39; \ -S /opt/data/data_16303/mysql.sock \ --single-transaction --no-autocommit \ --master-data=2 --skip-lock-tables --databases &gt;`date +%F`-datebases_name3.sql # 导出全部库 $ /usr/local/mysql/bin/mysqldump -u root -p&#39;passowrd&#39; \ -S /opt/data/data_16303/mysql.sock \ --all-databases --lock-tables=false \ --routines --single_transaction --flush-logs \ --skip-lock-tables --master-data=1 \ | gzip &gt;/root/mysql-all-`date +%F_%H%M%S`.sql.gz $ mysqldump -uroot -p --all-databases &gt; /tmp/all_databases.sql # 导出单个库 $ /bin/mysqldump -uroot -p&#39;passowrd&#39; \ --set-gtid-purged=OFF --single-transaction \ --master-data=1 --flush-logs \ -S /opt/data/data_16303/mysql.sock \ database | gzip &gt;/root/database`date +%F_%H%M%S`.sql.gz # 导出指定表 $ bin/mysql -u root -p&#39;password&#39; \ -S /opt/data/data_16303/mysql.sock \ -e &#39;select table_name from information_schema.tables where table_schema like &#34;game\-center\_jbty&#34;;&#39;|egrep &#34;.*record&#34; | xargs /bin/mysqldump -u root -p&#39;password&#39; -S /opt/data/data_16303/mysql.sock databases_name -t --tables &gt;tables_name.sql $ mysqldump -uroot -p --databases databases_name &gt; /tmp/databases_name.sql $ mysqldump -uroot -p --databases databases_name tables_name &gt; /tmp/databases_name_tables_name.sql 使用Mysql脚本备份并通知Telegram $ cat &gt;/opt/script/Backup_Mysql.sh&lt;&lt;-EOF #!/bin/bash DATA=$(date +%F_%H%M%S) ## set ff=unix # 修改换行符 ## 定义备份目录 MYSQL_BACKUP_PATH=/opt/backup/ ## 定义Telegram 机器人ID和报警组 TELEGRAM_BOT_ID=&#39;Telegram BOT_ID:BOT_Key&#39; TELEGRAM_GROUP_ID=&#39;GROUP_ID&#39; ## 定义连接数据库 账户密码IP USER_NAME=&#39;backup&#39; USER_PASSWORD=&#39;pass&#39; DATABASES=&#39;databases name&#39; # 备份表用 USER_HOST_1=&#39;IP_1&#39; USER_HOST_2=&#39;IP_2&#39; ## 过滤数据库, xargs和sed &#39;1d&#39;效果一样 DATABASES_1=`/bin/mysql -u${USER_NAME} -p&#34;${USER_PASSWORD}&#34; -h&#34;${USER_HOST_1}&#34; -e &#39;show databases;&#39; | grep -E -v &#34;sys|mysql|information_schema|performance_schema|Database&#34; | /bin/xargs` ## DATABASES_2=`/bin/mysql -u${USER_NAME} -p&#34;${USER_PASSWORD}&#34; -h&#34;${USER_HOST_2}&#34; -e &#39;show databases;&#39; | grep -E -v &#34;sys|mysql|information_schema|performance_schema|Database&#34; | sed &#39;1d&#39;` ## 检测备份目录是否存在，不存在就创建 ## /bin/test -d /opt/backup function TEST_BACKUP_DIR() { if [ ! -d ${MYSQL_BACKUP_PATH} ];then /bin/mkdir -p ${MYSQL_BACKUP_PATH} fi } ## 开始准备备份数据库 cd ${MYSQL_BACKUP_PATH} /bin/curl -X POST &#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage&#34; -d &#34;chat_id=${TELEGRAM_GROUP_ID}&amp;text=开始备份：${DATABASES_1} ${DATABASES_2} 数据库&#34; for i in ${DATABASES_1};do /usr/local/mysql/bin/mysqldump -u${USER_NAME} -p&#34;${USER_PASSWORD}&#34; -h${USER_HOST_1} --single-transaction --no-autocommit --master-data=1 --skip-lock-tables ${i} &gt; ${MYSQL_BACKUP_PATH}${i}-`date +%F`.sql done if [ $? -eq 0 ];then /bin/tar -zcvf ${MYSQL_BACKUP_PATH}${i}-`date +%F`.tar.gz ${i}-`date +%F`.sql /bin/curl -X POST &#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage&#34; -d &#34;chat_id=${TELEGRAM_GROUP_ID}&amp;text=${DATABASES_1} ${DATABASES_2} 数据库备份完成&#34; else /bin/curl -X POST &#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage&#34; -d &#34;chat_id=${TELEGRAM_GROUP_ID}&amp;text=${DATABASES_1} ${DATABASES_2} 数据库备份失败&#34; fi /bin/rm -rf ${MYSQL_BACKUP_PATH}*.sql ## 备份数据表 function BACKUP_MYSQL_TABLES() { cd ${MYSQL_BACKUP_PATH} for DATABASES in ${DATABASES_1};do TABLES_1=$(/bin/mysql -u${USER_NAME} -p&#34;${USER_PASSWORD}&#34; -h&#34;${USER_HOST_1}&#34; ${DATABASES} -e &#34;show tables;&#34;|sed &#39;1d&#39;) for I in ${TABLES_1};do /usr/local/mysql/bin/mysqldump -u${USER_NAME} -p&#34;${USER_PASSWORD}&#34; -h${USER_HOST_1} --single-transaction --no-autocommit --master-data=1 --skip-lock-tables ${I} &gt; ${MYSQL_BACKUP_PATH}${i}-`date +%F`.sql done /bin/tar -zcvf ${MYSQL_BACKUP_PATH}${DATABASES}-`date +%F`.tar.gz *.sql /bin/rm -rf ${MYSQL_BACKUP_PATH}*.sql done if [ $? -eq 0 ];then /bin/curl -X POST &#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage&#34; -d &#34;chat_id=${TELEGRAM_GROUP_ID}&amp;text=${DATABASES_1} ${DATABASES_2} 数据库备份完成&#34; else /bin/curl -X POST &#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage&#34; -d &#34;chat_id=${TELEGRAM_GROUP_ID}&amp;text=${DATABASES_1} ${DATABASES_2} 数据库备份失败&#34; fi } /bin/find ${MYSQL_BACKUP_PATH} -name &#34;databases-*&#34; -mtime +15 -exec rm {} \; EOF 数据库还原、导入 # 第一种方式 $ /bin/mysql -u root -p&#39;passowrd&#39; -S /opt/data/data_16303/mysql.sock &lt; /root/all.sql # 第二种方式 mysql&gt; use mysql; mysql&gt; source /root/databases.sql # 当前目录绝对路径 .qp文件数据库恢复 $ xbstream -x -p 4 &lt; ./databases.qp -C /opt/mysql/backup 使用innobackupex与xtrabackup备份数据库 安装 XtraBackup 、 innobackupex备份恢复+增量备份与恢复 、 Linux运维 mysql数据库的备份与恢复 # 添加yum源 $ wget -O /etc/yum.repos.d/epel.repo http://mirrors.aliyun.com/repo/epel-6.repo # 安装依赖包 $ yum -y install perl perl-devel libaio libaio-devel perl-Time-HiRes perl-DBD-MySQL # 下载rpm包 $ wget https://downloads.percona.com/downloads/Percona-XtraBackup-2.4/Percona-XtraBackup-2.4.27/binary/redhat/7/x86_64/percona-xtrabackup-24-2.4.27-1.el7.x86_64.rpm # 安装 $ yum -y install percona-xtrabackup-24-2.4.27-1.el7.x86_64.rpm 手动备份 2.1 完整以及增量备份 # 完整备份 $ innobackupex --host=IP --user=name --password=123456 --prot=3306 --no-timestamp /opt/backup/ # 增量备份 基于全量备份实现增量备份，增量备份只支持Innodb $ innobackupex --host=IP --user=root --password=123456 --prot=3306 --no-timestamp --incremental /opt/backup/ --incremental-basedir=/opt/backup/$(date +%F_%T) 2.2 数据库恢复流程 # 1.拷贝备份到data16303(只拷贝日期文件夹下面的文件) # 2.cd /opt/data16303 $ innobackupex --defaults-file=/opt/conf/my_16303.cnf --decompress --parallel=8 ./ # 3.删除所有.qp文件 # 4.恢复数据库(全量) $ cd /opt/data16303 $ innobackupex --defaults-file=/opt/conf/my_16303.cnf --apply-log --use-memory=4G ./ # 参数解释 --decompress # 该选项表示解压--compress选项压缩文件 --parallel # 该选项表示允许多个文件同时解压。为了解压，qpress工具必须有安装并且访问这个文件的权限。这个进程将在同一个位置移除原来的压缩/加密文件。 --apply-log # 该选项表示同xtrabackup的--prepare参数,一般情况下,在备份完成后，数据尚且不能用于恢复操作，因为备份的数据中可能会包含尚未提交的事务或已经提交但尚未同步至数据文件中的事务。因此，此时数据 文件仍处理不一致状态。 --apply-log # 的作用是通过回滚未提交的事务及同步已经提交的事务至数据文件使数据文件处于一致性状态。 2.3 手动恢复 $ service mysql stop # 初始化全量备份 $ innobackupex --apply-log --redo-only /opt/backup/ --incremental-dir=/opt/backup/$(date +%F_%T) # 初始化整合增量备份 $ innobackupex --apply-log --redo-only /data/backup/2017-08-24_22-57-43 --incremental-dir=/data/backup/2017-08-24_23-10-21 # 把整合好的增量再次初始化 $ innobackupex --apply-log /data/backup/2017-08-24_22-57-43 # 备份MySQL下data数据目录要恢复的数据库 $ mv /usr/local/mysql/data/ceshi/ /opt/backup/$(date +%F_%T)/ # 把整合后的全量备份目录下要恢复的数据库复制到MySQL下data目录 $ cp -a /opt/backup/quanliang/ceshi /usr/local/mysql/data/ # 重新赋予属组mysql权限 $ chown -R mysql.mysql /usr/local/mysql/data/ # 启动数据库 $ service mysql start 2.4 使用--copy参数实现备份恢复 $ service mysql stop # 把data数据目录下数据进行备份 $ cp -a /usr/local/mysql/data/* /opt/backup/$(date +%F_%T)/ # 把要恢复的数据备份生成 $ innobackupex --apply-log --redo-only /opt/backup/quanliang/ceshi_danku/ # 这个是单库备份目录 # data目录必须为空 $ innobackupex --copy-back /opt/backup/quanliang/ceshi_danku/ # 重新赋予属组权限 $ chown -R mysql.mysql /usr/local/mysql/data/ $ service mysql start 使用Mysql脚本备份并通知钉钉接口 $ cat &gt;/opt/script/Backup_Mysql_innobackupex.sh&lt;&lt;-EOF #!/bin/bash ## ***************************************************************# ## Create: DBA ## ***************************************************************# ## echo `hostname -I` |sed &#39;s/ /#/g&#39; - &gt;/tmp/ipaddr.txt # 定义Telegram 机器人ID和报警组 TELEGRAM_BOT_ID=&#39;Telegram bot_id:bot_key&#39; TELEGRAM_GROUP_ID=&#39;GROUP_ID&#39; IP_ADDRE=$(hostname -I |awk &#39;{print $1}&#39;) USER_NAME=&#39;backup&#39; USER_PASSWORD=&#39;IvV8BhpvHb/7EA==&#39; DATABASES=&#39;databases name&#39; backup_time=`date +&#39;%Y%m%d%m&#39;` backup_base=&#34;/opt/backup/dbback&#34; backup_dir=&#34;$backup_base/full&#34; backup_log=&#34;$backup_base/log/xtra_${backup_time}.log&#34; slave_days=0 ## 钉钉接口 function SendToDingding_error(){ #Dingding_Url=&#34;https://oapi.dingtalk.com/robot/send?access_token=d5201a579163dc6045b6da6d8dbc1cdc1d935698050971ceddb5a8956e9507ee&#34; Dingding_Url=&#34;https://api.telegram.org/bot${TELEGRAM_BOT_ID}/sendMessage?chat_id=${TELEGRAM_GROUP_ID}&amp;text=%22${IP_ADDRE}mysqlbak%20failure!Please check %22&#34; # 发送钉钉消息 curl &#34;${Dingding_Url}&#34; -H &#39;Content-Type: application/json&#39; -d &#34; { \&#34;actionCard\&#34;: { \&#34;title\&#34;: \&#34;$1\&#34;, \&#34;text\&#34;: \&#34;$2\&#34;, \&#34;hideAvatar\&#34;: \&#34;0\&#34;, \&#34;btnOrientation\&#34;: \&#34;0\&#34;, \&#34;btns\&#34;: [ { \&#34;title\&#34;: \&#34;$1\&#34;, \&#34;actionURL\&#34;: \&#34;\&#34; } ] }, \&#34;msgtype\&#34;: \&#34;actionCard\&#34; }&#34; } ## 安装备份工具 innobackupex 或 xtrabackup if [ ! -x /usr/bin/innobackupex ];then yum -y install http://www.percona.com/downloads/percona-release/redhat/0.1-4/percona-release-0.1-4.noarch.rpm yum -y install percona-xtrabackup-24 qpress fi ## 开始创建目录 if [ ! -d ${backup_dir} ];then mkdir -p ${backup_dir} fi if [ ! -d ${backup_base}/log ];then mkdir -p ${backup_base}/log fi start_time=`date +&#39;%Y%m%d_%H:%M:%S&#39;` start_file=`date +&#39;%Y-%m-%d_%H-%M-%S&#39;` ## 开始备份数据库 echo -e &#34;`date +&#39;%Y-%m-%d %H:%M:%S&#39;` 开始物理备份数据库 ${ipaddr} ...&#34; &gt;&gt; ${backup_log} /usr/bin/innobackupex --defaults-file=/opt/conf/my_16303.cnf --user=${backup_user} --password=${backup_password} --host=&#39;localhost&#39; --socket=/opt/data/data_16303/mysql.sock --use-memory=1G --compress --compress-threads=32 --parallel=3 --slave-info ${backup_dir} 2&gt;&gt;${backup_log} if [ $? -ne 0 ];then echo -e &#34;`date +&#39;%Y%m%d_%H:%M:%S&#39;` 备份数据库发生错误,具体看日志&#34; &gt;&gt; ${backup_log} Subject=&#34;物理备份xtra备份失败&#34; Body=&#34;&#39;${ipaddr}&#39;_物理备份失败,请参考日志:${backup_log}&#34; SendToDingding_error $Subject $Body exit 1 fi cd ${backup_dir} file_time=`date +&#39;%Y-%m-%d&#39;` flie_name=`ls -l | grep &#34;$file_time&#34;|tail -n 1|awk &#39;{print $9}&#39;` tar -zcf ${file_time}.tar.gz ${flie_name} rm -rf ${flie_name} ## rsync -avz if [ ! -z &#34;`tail -1 ${backup_log} | grep &#39;completed OK&#39;`&#34; ]; then finish_time=`date +&#39;%Y%m%d_%H:%M:%S&#39;` file_size=`du -sm ${backup_dir} |awk &#39;{print $1}&#39;` echo -e &#34;${ipaddr}数据库xtrabackup物理备份工作完成!
 开始时间：${start_time} 结束时间：${finish_time}
 备份目录${backup_dir}
 备份文件大小${file_size} MB&#34; &gt;&gt; ${backup_log} # 删除以前的备份 echo -e &#34;`date +&#39;%Y%m%d_%H:%M:%S&#39;` 开始删除${slave_days}天以前的备份&#34; &gt;&gt; ${backup_log} cd ${backup_base} for tfile in $(/usr/bin/find ${backup_dir} -mindepth 1 -maxdepth 1 -mtime +${slave_days}) do cd ${backup_dir} &amp;&amp; rm -rf ${tfile} 2&gt;&gt;${backup_log} echo -e &#34;---- delete file :${file} -----&#34; &gt;&gt; ${backup_log} done echo -e &#34;`date +&#39;%Y%m%d_%H%M%S&#39;` 删除${slave_days}天以前的备份-完成&#34; &gt;&gt; ${backup_log} find $backup_base/log -mindepth 1 -maxdepth 1 -mtime +${slave_days} -type f |xargs rm -f else echo -e &#34;`date +&#39;%Y%m%d_%H:%M:%S&#39;` 备份数据库发生错误,具体看日志&#34; &gt;&gt; ${backup_log} Subject=&#34;物理备份xtra备份失败&#34; Body=&#34;${ipaddr}_物理备份失败,请参考日志:${backup_log}&#34; SendToDingding_error $Subject $Body fi exit EOF

Redis安装 Redis安装包 Redis依赖gcc与gcc-c++，而Redis5.0以上需要更高版本gcc 1.1 安装Gcc $ yum -y install gcc gcc-c++ centos-release-scl wget git 1.2 安装高版本gcc $ yum -y install devtoolset-9-gcc devtoolset-9-gcc-c++ devtoolset-9-binutils # 临时生效 $ echo &#39;scl enable devtoolset-9 bash&#39; # 添加到环境变量永久生效 $ echo &#34;source /opt/rh/devtoolset-9/enable&#34; &gt;&gt;/etc/profile $ source /etc/profile 安装Redis 2.1 下载tar包到指定目并解压 $ wget -P /usr/local/src/ http://download.redis.io/releases/redis-5.0.7.tar.gz # 下载到指定目录 2.2 解压到指定目录并重命名 $ mkdir -p /usr/local/redis &amp;&amp; tar zxvf /usr/local/src/redis-5.0.7.tar.gz -C /usr/local/redis --strip-components 1 2.3 配置redis $ cd /usr/local/redis $ make MALLOC=libc 2.4 执行安装 $ make PREFIX=/usr/local/redis install 2.5 修改配置文件daemonize参数能后台启动以及使用密码连接注释不可以在行尾 $ echo &#39;# redis后台运行 daemonize yes # Redis的pid文件存放位置 pidfile /usr/local/redis/logs/redis_6379.pid # Redis的日志文件存放位置 logfile /usr/local/redis/logs/redis_6379.log # 端口号 port 6379 # 最好是本机IP bind 192.168.176.131 # 超时时间300秒 timeout 300 # 缓存库的个数 databases 8 # 将数据库转储到的文件名 dbfilename dump-16379.db # 数据存放目录 dir ./ # 主库密码 masterauth password # 连接密码 requirepass password &#39;&gt; /usr/local/redis/redis.conf 2.6 启动Redis $ /usr/local/redis/bin/redis-server /usr/local/redis/redis.conf 编写常规启动文件 $ echo &#39;#!/bin/sh # Simple Redis init.d script conceived to work on Linux systems # as it does use of the /proc filesystem. # chkconfig: 2345 90 10 # description: Redis is a persistent key-value database REDISPORT=6379 EXEC=/usr/local/redis/bin/redis-server CLIEXEC=/usr/local/redis/bin/redis-cli $CLIEXEC -a &#34;Redis&#34; -p $REDISPORT shutdown PIDFILE=/var/run/redis_${REDISPORT}.pid CONF=&#34;/usr/local/redis/redis.conf&#34; case &#34;$1&#34; in start) if [ -f $PIDFILE ] then echo &#34;$PIDFILE exists, process is already running or crashed&#34; else echo &#34;Starting Redis server...&#34; $EXEC $CONF fi ;; stop) if [ ! -f $PIDFILE ] then echo &#34;$PIDFILE does not exist, process is not running&#34; else PID=$(cat $PIDFILE) echo &#34;Stopping ...&#34; $CLIEXEC -p $REDISPORT shutdown while [ -x /proc/${PID} ] do echo &#34;Waiting for Redis to shutdown ...&#34; sleep 1 done echo &#34;Redis stopped&#34; fi ;; *) echo &#34;Please use start or stop as first argument&#34; ;; esac&#39; &gt; /etc/init.d/redis $ chmod +x /etc/init.d/redis $ chkconfig redis on # 启动并查看端口号 $ service redis start $ netstat -nuplt | grep 6379 编写指定目录启动文件 $ echo &#39;## 目录 REDIS_PATH=&#34;/opt/apps/redis&#34; sql_conf_dir=&#39;/opt/apps/redis&#39; sql_conf_file=$(ls $sql_conf_dir/* |egrep conf$) sql_user=&#39;admin&#39; ## start_redis(){ sql_pid=$(ps -ef |egrep redis-server |egrep -v root |awk &#39;{print $2}&#39;) [ ! -z ${sql_pid} ] &amp;&amp; echo -e &#34;
\033[31mredis running...\033[0m
&#34; &amp;&amp; exit su ${sql_user} -s /bin/bash -c &#34;${REDIS_PATH}/bin/redis-server ${sql_conf_file}&#34; } stop_redis(){ sql_pid=$(ps -ef |egrep redis-server |egrep -v root |awk &#39;{print $2}&#39;) [ -z ${sql_pid} ] &amp;&amp; echo -e &#34;
\033[31mredis not run...\033[0m
&#34; &amp;&amp; exit su swadmin -s /bin/bash -c &#34;kill ${sql_pid}&#34; } ### Finally the input handling. case &#34;$1&#34; in start) start_redis ;; stop) stop_redis ;; *) echo &#34;Usage: service redis {start|stop}&#34; exit 1 ;; esac exit &#39;&gt; /etc/init.d/redis $ chmod +x /etc/init.d/redis $ chkconfig redis on 部署脚本 $ cat &gt;redis-install.sh&lt;&lt;EOF #!/bin/bash sed -i &#34;N;56isource /opt/rh/devtoolset-9/enable&#34; /etc/profile id swadmin if [ $? -ne 0 ];then #创建普通用户部署运行Redis groupadd swadmin &amp;&amp; useradd -g swadmin swadmi sleep 1 echo &#34;20210623@123&#34;|passwd --stdin2 swadmin &amp;&gt;/dev/null #给swadmin用户设置密码 fi mkdir -p /opt/{src,conf,data,apps} /opt/data/{data_17693,data_17694,data_17695,data_16303} chown -R swadmin. /opt/* echo &#34;#########Start/Stop Service############### Cmnd_Alias SWADMIN_START_SERVICES = /etc/init.d/redis, /opt/* #授予普通用户启动停止权限 swadmin ALL=(ALL)NOPASSWD:SWADMIN_START_SERVICES&#34; &gt;/etc/sudoers.d/swadmin chmod 660 /etc/sudoers.d/swadmin #Redis依赖gcc 与gcc-c++,#Redis5.0以上需要高版本gcc yum -y install gcc gcc-c++ centos-release-scl wget git yum -y install devtoolset-9-gcc devtoolset-9-gcc-c++ devtoolset-9-binutils echo &#39;scl enable devtoolset-9 bash&#39; echo &#34;source /opt/rh/devtoolset-9/enable&#34; &gt;&gt;/etc/profile source /etc/profile ##如遇因缺少gcc报错先执行 ##make distclean 再meke su swadmin -c &#34; git clone https://admin:&#34;frTd3KbJct_pgoBstA5f&#34;@gitlab.com/usererge/redis-conf.git /opt/conf/ wget -P /opt/src/ http://download.redis.io/releases/redis-5.0.7.tar.gz mkdir -p /opt/apps/redis &amp;&amp; tar zxvf /opt/src/redis-5.0.7.tar.gz -C /opt/apps/redis --strip-components 1 cd /opt/apps/redis/ make MALLOC=libc make PREFIX=/opt/apps/redis install /opt/apps/redis/src/redis-server /opt/conf/redis-conf/re_17693.conf &amp; &#34; source /etc/profile EOF
